fn load_temp_int(
    bin: &Binary,
    dfg: &DataFlowGraph,
    reg_alloc: &LinearScanAlloc,
) -> Vec<Option<String>> {
    let op1 = bin.lhs();
    let op2 = bin.rhs();

    let mut asm: String = String::new();
    let leftreg: Option<String>;
    let rightreg: Option<String>;

    // Handle OP1
    if let ValueKind::Integer(int) = dfg.value(op1).kind() {
        let val = int.value();
        if val != 0 {
            leftreg = Some(String::from("t5"));
            asm += &format!("\tli\tt5, {}\n", val);
        } else {
            leftreg = Some(String::from("x0"));
        }
    } else {
        // Look up register from allocator
        leftreg = reg_alloc.get_reg(op1).cloned();
    }

    // Handle OP2
    if let ValueKind::Integer(int) = dfg.value(op2).kind() {
        let val = int.value();
        if val != 0 {
            rightreg = Some(String::from("t6"));
            asm += &format!("\tli\tt6, {}\n", val);
        } else {
            rightreg = Some(String::from("x0"));
        }
    } else {
        // Look up register from allocator
        rightreg = reg_alloc.get_reg(op2).cloned();
    }

    vec![Some(asm), leftreg, rightreg]
}

// use std::str::FromStr;
use crate::ast::*;
use std::boxed::Box;
// lalrpop 里的约定
grammar;

// 约束 lexer 的行为
match {
  // 跳过空白符和注释
  r"\s*" => {},
  r"//[^\n\r]*[\n\r]*" => {},
  r"/\*([^*]|\*[^/])*\*/" => {},
  // 剩下的情况采用默认方式处理
  _
}

// 定义 CompUnit, 其返回值类型为 String
// parser 在解析完成后的行为是返回 FuncDef 的值
pub CompUnit: CompUnit = <func_def: FuncDef> => CompUnit { func_def };

// 同上, 不解释
FuncDef: FuncDef = {
  <func_type: RawType> <ident: Ident> "(" <func_params: FuncFParams> ")" <block: Block> => {
    FuncDef { func_type, ident, func_params, block }
  }
}

RawType: RawType = "int" => RawType::Int;

Block: Block = "{" <stmt: StmtList> "}" => Block { stmt };
StmtList = <Stmt*>;
Stmt: Stmt = "return" <exp: Exp> ";" => Stmt::Return(exp);
Exp: Exp = <AddExp>;

LOrExp: Exp  = {
    <lhs: LOrExp> "||" <rhs: LAndExp> => Exp::Binary { op: BinaryOp::Or, lhs: Box::new(lhs), rhs: Box::new(rhs) },
    <exp: LAndExp> => exp,
}



AddExp: Exp = {
  <lhs: AddExp> "+" <rhs: MulExp> => Exp::Binary { op: BinaryOp::Add, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <lhs: AddExp> "-" <rhs: MulExp> => Exp::Binary { op: BinaryOp::Sub, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <exp: MulExp> => exp,
}

MulExp: Exp = {
  <lhs: MulExp> "*" <rhs: UnaryExp> => Exp::Binary { op: BinaryOp::Mul, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <lhs: MulExp> "/" <rhs: UnaryExp> => Exp::Binary { op: BinaryOp::Div, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <lhs: MulExp> "%" <rhs: UnaryExp> => Exp::Binary { op: BinaryOp::Mod, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <exp: UnaryExp> => exp,
}

UnaryExp: Exp = {
    <pexp: PrimaryExp> => pexp,
    <uop: UnaryOp> <uexp: UnaryExp> => Exp::Unary{op:uop, exp:Box::new(uexp)},
}
PrimaryExp: Exp = {
    "(" <exp: Exp> ")" => exp,
    <num: Number> => num,
}
UnaryOp: UnaryOp = {
    "+" => UnaryOp::Plus,
    "-" => UnaryOp::Minus,
    "!" => UnaryOp::Not,
}
Number: Exp = <num: IntConst> => Exp::Number(num);

FuncFParams: Vec<FuncFParam> = {
    () => Vec::new(),
    <head: FuncFParam> <tail: ("," <FuncFParam>)*> => {
        let mut params = vec![head];
        params.extend(tail);
        params
    }
}
FuncFParam: FuncFParam = <bt: RawType> <id: Ident> => FuncFParam { bt, id };

// 如果匹配到标识符, 就返回这个字符串
// 一对尖括号在此处指代的是正则表达式匹配到的字符串 (&str)
// 关于尖括号到底代表什么, 请 RTFM
Ident: String = <s: r"[_a-zA-Z][_a-zA-Z0-9]*"> => s.to_string();

// 对整数字面量的处理方式: 把匹配到的字符串按对应进制转换成数字
IntConst: i32 = {
  <s: r"[1-9][0-9]*"> => i32::from_str_radix(s, 10).unwrap(),
  <s: r"0[0-7]*"> => i32::from_str_radix(s, 8).unwrap(),
  <s: r"0[xX][0-9a-fA-F]+"> => i32::from_str_radix(&s[2..], 16).unwrap(),
}

