}

MulExp: Exp = {
  <lhs: MulExp> "*" <rhs: UnaryExp> => Exp::Binary { op: BinaryOp::Mul, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <lhs: MulExp> "/" <rhs: UnaryExp> => Exp::Binary { op: BinaryOp::Div, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <lhs: MulExp> "%" <rhs: UnaryExp> => Exp::Binary { op: BinaryOp::Mod, lhs: Box::new(lhs), rhs: Box::new(rhs) },
  <exp: UnaryExp> => exp,
}

UnaryExp: Exp = {
    <pexp: PrimaryExp> => pexp,
    <uop: UnaryOp> <uexp: UnaryExp> => Exp::Unary{op:uop, exp:Box::new(uexp)},
}
PrimaryExp: Exp = {
    "(" <exp: Exp> ")" => exp,
    <num: Number> => num,
}
UnaryOp: UnaryOp = {
    "+" => UnaryOp::Plus,
    "-" => UnaryOp::Minus,
    "!" => UnaryOp::Not,
}
Number: Exp = <num: IntConst> => Exp::Number(num);

FuncFParams: Vec<FuncFParam> = {
    () => Vec::new(),
    <head: FuncFParam> <tail: ("," <FuncFParam>)*> => {
        let mut params = vec![head];
        params.extend(tail);
        params
    }
}
FuncFParam: FuncFParam = <bt: RawType> <id: Ident> => FuncFParam { bt, id };

